INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '87ce5a34-e888-416d-95c5-0cb7f58aad64',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vyper Fundamentals: Mastering Types, Visibility, and State Variables$escape$,
  $escape$Vyper, a Python-based smart contract language, provides a unique set of features for building robust and secure blockchain applications. When defining state variables, Vyper supports various types such as uint256, address, and bool. Visibility modifiers like public, private, and external can be used to control access to functions and state variables. For instance, the @external decorator can be used to expose functions to external contracts. Understanding these fundamentals is crucial for writing efficient and secure Vyper contracts.$escape$,
  $escape$a: uint256 = 5
b: address = 0x1234567890
@external
def greet() -> str: return 'Hello World!'$escape$,
  $escape$solidity$escape$,
