INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a8dc1e6a-cb35-4e13-995e-d07b2f71b1a9',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vyper Storage Layout — Optimizing SLOAD/SSTORE Costs$escape$,
  $escape$When storing data in Vyper smart contracts, it's essential to consider the storage layout to minimize SLOAD/SSTORE costs. Slots are 32-byte positions in the storage trie where contract variables are stored. To pack multiple variables into a single slot, use the `calldata` type, which allows for flexible packing. For example:
```
variable1: bytes32 = "0x1234567890abcdef" # 32 bytes
variable2: uint256 = 1234567890
# variable2 is packed into the last 32 bits of variable1's slot
```
To avoid storage collisions, use the `storage_layout` decorator to define the storage layout for your contract. This ensures that variables are stored in the correct slots.
```
@storage_layout
class MyContract: # storage_layout decorator defines the storage layout
    variable1: bytes32 = "0x1234567890abcdef"
    variable2: uint256 = 1234567890
```
By optimizing the storage layout, you can reduce SLOAD/SSTORE costs and improve contract performance.$escape$,
  $escape$```
variable1: bytes32 = "0x1234567890abcdef"
variable2: uint256 = 1234567890
```
@storage_layout
class MyContract:
    variable1: bytes32 = "0x1234567890abcdef"
    variable2: uint256 = 1234567890
$escape$,
  $escape$vyper$escape$,
